    79→function normalizeOrgInput(orgRaw) {
    80→  let organization = String(orgRaw || '').trim();
    81→  if (!organization) return '';
    82→
    83→  if (organization.includes('://')) {
    84→    try {
    85→      const parsed = new URL(organization);
    86→      if (parsed.hostname === 'dev.azure.com') {
    87→        organization = parsed.pathname.split('/').filter(Boolean)[0] || '';
    88→      } else if (parsed.hostname.endsWith('.visualstudio.com')) {
    89→        organization = parsed.hostname.split('.')[0] || '';
    90→      }
    91→    } catch (_) {
    92→      // keep original
    93→    }
    94→  }
    95→  return organization.trim();
    96→}
