   102→function adoHeaders(pat) {
   103→  const auth = Buffer.from(`:${pat}`).toString('base64');
   104→  return {
   105→    Authorization: `Basic ${auth}`,
   106→    Accept: 'application/json',
   107→    // KEY: avoid redirecting to interactive AAD sign-in (HTML)
   108→    'X-TFS-FedAuthRedirect': 'Suppress',
   109→    // Optional but helpful
   110→    'User-Agent': 'DevOpsDashboard/1.0'
   111→  };
   112→}
