   118→function isLikelyHtml(ct, body) {
   119→  const c = (ct || '').toLowerCase();
   120→  const b = (body || '').trim().toLowerCase();
   121→  return c.includes('text/html') || b.startsWith('<!doctype html') || b.startsWith('<html');
   122→}
