   398→app.patch('/api/azuredevops/update/:id', async (req, res) => {
   399→  try {
   400→    const { id } = req.params;
   401→    const {
   402→      organization,
   403→      project,
   404→      personalAccessToken,
   405→      apiVersion = '7.0',
   406→      updates
   407→    } = req.body || {};
   408→
   409→    if (!organization || !project || !personalAccessToken) {
   410→      return res.status(400).json({ error: 'Missing organization/project/personalAccessToken' });
   411→    }
   412→
   413→    const base =
   414→      `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}`;
   415→
   416→    const url =
   417→      `${base}/_apis/wit/workitems/${encodeURIComponent(id)}?api-version=${encodeURIComponent(apiVersion)}`;
   418→
   419→    const patch = [];
   420→
   421→    // ---- Fields (use replace) ----
   422→    if (updates?.title != null) {
   423→      patch.push({ op: 'replace', path: '/fields/System.Title', value: String(updates.title) });
   424→    }
   425→    if (updates?.description != null) {
   426→      patch.push({ op: 'replace', path: '/fields/System.Description', value: String(updates.description) });
   427→    }
   428→    if (updates?.state != null || updates?.status != null) {
   429→      patch.push({
   430→        op: 'replace',
   431→        path: '/fields/System.State',
   432→        value: String(updates.state ?? updates.status)
   433→      });
   434→    }
   435→    if (updates?.priority != null) {
   436→      patch.push({
   437→        op: 'replace',
   438→        path: '/fields/Microsoft.VSTS.Common.Priority',
   439→        value: Number(updates.priority)
   440→      });
   441→    }
   442→    if (updates?.areaPath != null) {
   443→      patch.push({ op: 'replace', path: '/fields/System.AreaPath', value: String(updates.areaPath) });
   444→    }
   445→
   446→    // Tags (enforced)
   447→    if (updates?.tags != null) {
   448→      patch.push({
   449→        op: 'replace',
   450→        path: '/fields/System.Tags',
   451→        value: ensureAllowedTags(updates.tags)
   452→      });
   453→    }
   454→
   455→    // ---- Parent EPIC linking ----
   456→    // Expect updates.parentId = epic work item id (number)
   457→    if (updates?.parentId != null && String(updates.parentId).trim() !== '') {
   458→      const epicId = Number(updates.parentId);
   459→      if (!Number.isFinite(epicId) || epicId <= 0) {
   460→        return res.status(400).json({ error: 'Invalid updates.parentId (epic id)' });
   461→      }
   462→
   463→      // IMPORTANT: to remove existing parent relation we need its index.
   464→      // We fetch current work item relations first.
   465→      const getUrl =
   466→        `${base}/_apis/wit/workitems/${encodeURIComponent(id)}?` +
   467→        `api-version=${encodeURIComponent(apiVersion)}&$expand=relations`;
   468→
   469→      const currentResp = await fetch(getUrl, {
   470→        headers: { ...adoHeaders(personalAccessToken), Accept: 'application/json' }
   471→      });
   472→
   473→      const current = await currentResp.json().catch(() => ({}));
   474→      if (!currentResp.ok) {
   475→        return res.status(currentResp.status).json({
   476→          error: 'Failed to read work item for linking',
   477→          bodyPreview: JSON.stringify(current).slice(0, 500)
   478→        });
   479→      }
   480→
   481→      const relations = Array.isArray(current.relations) ? current.relations : [];
   482→
   483→      // Parent link on child = Hierarchy-Reverse
   484→      const parentRelIndexes = relations
   485→        .map((r, idx) => ({ r, idx }))
   486→        .filter(x => x.r?.rel === 'System.LinkTypes.Hierarchy-Reverse');
   487→
   488→      // remove ALL existing parents (usually only one)
   489→      // remove from highest index to lowest so indexes don’t shift
   490→      parentRelIndexes
   491→        .sort((a, b) => b.idx - a.idx)
   492→        .forEach(({ idx }) => {
   493→          patch.push({ op: 'remove', path: `/relations/${idx}` });
   494→        });
   495→
   496→      // add new parent relation
   497→      const epicUrl = `${base}/_apis/wit/workitems/${encodeURIComponent(epicId)}`;
   498→      patch.push({
   499→        op: 'add',
   500→        path: '/relations/-',
   501→        value: {
   502→          rel: 'System.LinkTypes.Hierarchy-Reverse',
   503→          url: epicUrl,
   504→          attributes: { comment: 'Linked to Epic from dashboard' }
   505→        }
   506→      });
   507→    }
   508→
   509→    // If nothing to patch, return friendly error
   510→    if (patch.length === 0) {
   511→      return res.status(400).json({ error: 'No updates provided' });
   512→    }
   513→
   514→    const resp = await fetch(url, {
   515→      method: 'PATCH',
   516→      headers: {
   517→        ...adoHeaders(personalAccessToken),
   518→        'Content-Type': 'application/json-patch+json',
   519→        Accept: 'application/json'
   520→      },
   521→      body: JSON.stringify(patch)
   522→    });
   523→
   524→    const json = await resp.json().catch(() => ({}));
   525→    if (!resp.ok) {
   526→      return res.status(resp.status).json({
   527→        error: 'Update failed',
   528→        bodyPreview: JSON.stringify(json).slice(0, 800),
   529→        sentPatch: patch
   530→      });
   531→    }
   532→
   533→    return res.json(json);
   534→  } catch (e) {
   535→    return res.status(500).json({ error: e.message || 'Update failed' });
   536→  }
   537→});

