     5→// Shared settings cache and save logic for persistent state
     6→const settingsCache = { current: null, loaded: false, listeners: new Set() };
     7→
     8→function loadSettings() {
     9→  if (settingsCache.loaded) return Promise.resolve(settingsCache.current);
    10→  return fetch('/api/settings')
    11→    .then(r => r.ok ? r.json() : {})
    12→    .then(data => { settingsCache.current = data; settingsCache.loaded = true; return data; })
    13→    .catch(() => { settingsCache.current = {}; settingsCache.loaded = true; return {}; });
    14→}
    15→
    16→let saveTimer = null;
    17→function saveSettings(allSettings) {
    18→  settingsCache.current = { ...settingsCache.current, ...allSettings };
    19→  clearTimeout(saveTimer);
    20→  saveTimer = setTimeout(() => {
    21→    fetch('/api/settings', {
    22→      method: 'POST',
    23→      headers: { 'Content-Type': 'application/json' },
    24→      body: JSON.stringify(settingsCache.current)
    25→    }).catch(() => {});
    26→  }, 500);
    27→}
