    29→// Custom hook for API-backed persistent state
    30→function usePersistentState(key, initialValue) {
    31→  const [value, setValueRaw] = useState(initialValue);
    32→
    33→  useEffect(() => {
    34→    loadSettings().then(data => {
    35→      if (data[key] !== undefined) setValueRaw(data[key]);
    36→    });
    37→  }, [key]);
    38→
    39→  const setValue = useCallback((updater) => {
    40→    setValueRaw(prev => {
    41→      const next = updater instanceof Function ? updater(prev) : updater;
    42→      saveSettings({ [key]: next });
    43→      return next;
    44→    });
    45→  }, [key]);
    46→
    47→  return [value, setValue];
    48→}
