#### 3.3 Create electron/api/settings.js (NEW)
**Purpose:** Settings persistence (migrated from server.js lines 53-73)

**Migration from Express:**
- `app.get('/api/settings')` → `ipcMain.handle('settings:load')`
- `app.post('/api/settings')` → `ipcMain.handle('settings:save')`
- Use `app.getPath('userData')` instead of `__dirname/data`

**Code structure:**
```javascript
const { app } = require('electron');
const fs = require('fs');
const path = require('path');

const getSettingsPath = () => {
  const userDataPath = app.getPath('userData');
  return path.join(userDataPath, 'settings.json');
};

const register = (ipcMain) => {
  ipcMain.handle('settings:load', async () => {
    try {
      const settingsPath = getSettingsPath();
      if (fs.existsSync(settingsPath)) {
        const data = fs.readFileSync(settingsPath, 'utf-8');
        return JSON.parse(data);
      }
      return {};
    } catch (error) {
      console.error('Failed to load settings:', error);
      return {};
    }
  });

  ipcMain.handle('settings:save', async (event, data) => {
    try {
      const settingsPath = getSettingsPath();
      const dirPath = path.dirname(settingsPath);
      if (!fs.existsSync(dirPath)) {
        fs.mkdirSync(dirPath, { recursive: true });
      }
      fs.writeFileSync(settingsPath, JSON.stringify(data, null, 2));
      return { ok: true };
    } catch (error) {
      console.error('Failed to save settings:', error);
      return { ok: false, error: error.message };
    }
  });
};

module.exports = { register };
```

**Data migration path:** Copy existing `S:\02_DevOps\data\settings.json` → `%APPDATA%\devops-dashboard\settings.json` on first run.

