const { app } = require('electron');
const fs = require('fs');
const path = require('path');

const getWorkitemsPath = () => {
  const userDataPath = app.getPath('userData');
  return path.join(userDataPath, 'workitems.json');
};

const readJsonArray = (filePath) => {
  try {
    if (!fs.existsSync(filePath)) return [];
    const raw = fs.readFileSync(filePath, 'utf8');
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch {
    return [];
  }
};

const writeJsonArray = (filePath, arr) => {
  const dirPath = path.dirname(filePath);
  if (!fs.existsSync(dirPath)) {
    fs.mkdirSync(dirPath, { recursive: true });
  }
  fs.writeFileSync(filePath, JSON.stringify(arr, null, 2), 'utf8');
};

const register = (ipcMain) => {
  ipcMain.handle('workitems:load', async () => {
    return readJsonArray(getWorkitemsPath());
  });

  ipcMain.handle('workitems:save', async (event, data) => {
    try {
      const arr = Array.isArray(data) ? data : [];
      writeJsonArray(getWorkitemsPath(), arr);
      return { ok: true, count: arr.length };
    } catch (error) {
      return { ok: false, error: error.message };
    }
  });
};

module.exports = { register };
```

