- Badge/tooltip for sync status

**Code structure:**
```javascript
const { Tray, Menu, nativeImage, app } = require('electron');
const path = require('path');

let tray = null;

function initTray(mainWindow) {
  const iconPath = path.join(__dirname, '../assets/icons/tray-icon.png');
  const icon = nativeImage.createFromPath(iconPath);

  tray = new Tray(icon.resize({ width: 16, height: 16 }));
  tray.setToolTip('DevOps Dashboard');

  const contextMenu = Menu.buildFromTemplate([
    {
      label: 'Show Dashboard',
      click: () => {
        mainWindow.show();
        mainWindow.focus();
      }
    },
    {
      label: 'Sync Now',
      click: () => {
        mainWindow.webContents.send('tray:sync-requested');
      }
    },
    { type: 'separator' },
    {
      label: 'Settings',
      click: () => {
        mainWindow.show();
        mainWindow.webContents.send('tray:open-settings');
      }
    },
    { type: 'separator' },
    {
      label: 'Quit',
      click: () => {
        app.isQuitting = true;
        app.quit();
      }
    }
  ]);

  tray.setContextMenu(contextMenu);

  // Click to toggle window
  tray.on('click', () => {
    if (mainWindow.isVisible()) {
      mainWindow.hide();
    } else {
      mainWindow.show();
      mainWindow.focus();
    }
  });

  return tray;
}

function updateTrayTooltip(message) {
  if (tray) {
    tray.setToolTip(`DevOps Dashboard - ${message}`);
  }
}

module.exports = { initTray, updateTrayTooltip };
```

