const { app } = require('electron');

function registerAutoStart() {
  // Check if this is the first run
  const settings = app.getLoginItemSettings();

  // Only set auto-start on first launch (don't force it)
  if (!settings.wasOpenedAtLogin && !settings.openAtLogin) {
    app.setLoginItemSettings({
      openAtLogin: true,
      openAsHidden: true, // Start minimized to tray
      args: ['--hidden']
    });
    console.log('Auto-start enabled for Windows');
  }
}

function setAutoStart(enabled) {
  app.setLoginItemSettings({
    openAtLogin: enabled,
    openAsHidden: enabled,
    args: enabled ? ['--hidden'] : []
  });
}

function isAutoStartEnabled() {
  return app.getLoginItemSettings().openAtLogin;
}

module.exports = { registerAutoStart, setAutoStart, isAutoStartEnabled };
```

