#### 3.16 Data migration script (NEW - Optional)
**Purpose:** Copy existing data on first launch

**Create electron/migrate.js:**
```javascript
const fs = require('fs');
const path = require('path');
const { app } = require('electron');

function migrateOldData() {
  const oldDataDir = path.join(__dirname, '..', 'data');
  const newDataDir = app.getPath('userData');

  if (!fs.existsSync(oldDataDir)) return;

  const files = ['settings.json', 'workitems.json', 'epics.json'];

  files.forEach(file => {
    const oldPath = path.join(oldDataDir, file);
    const newPath = path.join(newDataDir, file);

    if (fs.existsSync(oldPath) && !fs.existsSync(newPath)) {
      fs.copyFileSync(oldPath, newPath);
      console.log(`Migrated ${file} to userData`);
    }
  });
}

module.exports = { migrateOldData };
```

**Call in main.js:** `migrateOldData()` before `app.whenReady()`

